pipeline.evaluate:
(async () => {
  const limit = ${{ args.limit }};
  const typeFilter = '${{ args.type }}'.toLowerCase();
  let csrf = '';
  for (let i = 0; i < 10; i++) {
    csrf = document.querySelector('meta[name="csrf-token"]')?.content || '';
    if (csrf) break;
    await new Promise(r => setTimeout(r, 500));
  }
  if (!csrf) return [];
  const fields = 'baseSymbol,strikePrice,expirationDate,optionType,lastPrice,volume,openInterest,volumeOpenInterestRatio,volatility'.split(',');
  const fetchLimit = typeFilter !== 'all' ? limit * 3 : limit;
  const lists = ['options.unusual_activity.stocks.us', 'options.mostActive.us'];
  for (const list of lists) {
    try {
      const url = '/proxies/core-api/v1/options/get?list=' + list + '&fields=' + fields.join(',') + '&orderBy=volumeOpenInterestRatio&orderDir=desc&raw=1&limit=' + fetchLimit;
      const resp = await fetch(url, { credentials: 'include', headers: { 'X-CSRF-TOKEN': csrf } });
      if (!resp.ok) continue;
      const d = await resp.json();
      let items = d?.data || [];
      if (!items.length) continue;
      if (typeFilter !== 'all') {
        items = items.filter(i => ((i.raw || i).optionType || '').toLowerCase() === typeFilter);
      }
      return items.slice(0, limit).map(i => {
        const r = i.raw || i;
        return {
          symbol: r.baseSymbol || r.symbol,
          type: r.optionType,
          strike: r.strikePrice,
          expiration: r.expirationDate,
          last: r.lastPrice != null ? Number(r.lastPrice).toFixed(2) : null,
          volume: r.volume,
          openInterest: r.openInterest,
          volOiRatio: r.volumeOpenInterestRatio != null ? Number(r.volumeOpenInterestRatio).toFixed(2) : null,
          iv: r.volatility != null ? Number(r.volatility).toFixed(2) + '%' : null
        };
      });
    } catch(e) {}
  }
  return [];
})()
